import type { RefObject } from 'react';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { getOptionsInDisplayOrder, getPreparedOptions } from '../../helpers';
import type { Option } from '../../Select.types';

interface SelectKeyBoardNavigation<T> {
	enableKeyboardNavigation?: boolean;
	isOpen?: boolean;
	options?: Array<Option<T>>;
	handleClose?: () => void;
	multiple?: boolean;
	optionsRef?: React.MutableRefObject<HTMLDivElement>;
	inputRef?: RefObject<HTMLInputElement>;
	/** Ref на контейнер dropdown (filter + options). Используется для проверки фокуса внутри выпадашки. */
	dropdownRef?: RefObject<HTMLDivElement | null>;
	onMultiselectItem?: (item: Option<T>) => () => void;
	onSelectItem: (item: Option<T>) => () => void;
	onManualClickOption?: (option: T) => void;
	selectAll: boolean;
	filter?: boolean;
	filterValue?: string;
	filterFunction?: (options: Array<Option<T>>, filterValue: string) => Array<Option<T>>;
	groups?: Array<Option<string>>;
}

export const useSelectKeyBoardNavigation = <T>({
	enableKeyboardNavigation,
	isOpen,
	options,
	handleClose,
	multiple,
	optionsRef,
	onMultiselectItem,
	onSelectItem,
	onManualClickOption,
	selectAll,
	inputRef,
	dropdownRef,
	filter,
	filterValue,
	filterFunction,
	groups,
}: SelectKeyBoardNavigation<T>) => {
	const [focusedIndex, setFocusedIndex] = useState<number>(-1);
	const filteredOptions = useMemo(() => {
		const prepared = getPreparedOptions(options || [], filter, filterValue, filterFunction);
		return getOptionsInDisplayOrder(prepared, groups);
	}, [options, filter, filterValue, filterFunction, groups]);

	const getNextEnabledIndex = useCallback(
		(startIndex: number, direction: 1 | -1, maxIdx: number): number => {
			let nextIndex = startIndex + direction;
			while (nextIndex >= 0 && nextIndex <= maxIdx) {
				if (!filteredOptions[nextIndex]?.disabled) {
					return nextIndex;
				}
				nextIndex += direction;
			}
			return -1;
		},
		[filteredOptions],
	);

	const handleArrowKey = useCallback(
		(direction: 1 | -1, maxIdx: number) => {
			let startIndex: number;
			if (focusedIndex >= 0) {
				startIndex = focusedIndex;
			} else if (direction === 1) {
				startIndex = -1;
			} else {
				startIndex = maxIdx + 1;
			}
			const nextIndex = getNextEnabledIndex(startIndex, direction, maxIdx);
			if (nextIndex !== -1) {
				setFocusedIndex(nextIndex);
			}
		},
		[focusedIndex, getNextEnabledIndex],
	);

	const handleEnterKey = useCallback(() => {
		const option = filteredOptions[focusedIndex];
		if (!option || option.disabled) {
			return;
		}
		if (onManualClickOption) {
			onManualClickOption(option.value);
			return;
		}
		multiple ? onMultiselectItem?.(option)() : onSelectItem(option)();
		if (!multiple) {
			setFocusedIndex(-1);
		}
	}, [filteredOptions, focusedIndex, multiple, onManualClickOption, onMultiselectItem, onSelectItem]);

	const handleKeyDown = useCallback(
		(event: KeyboardEvent) => {
			const isInputFocused = document.activeElement === inputRef?.current;
			const isInDropdown = dropdownRef?.current?.contains(document.activeElement as Node) ?? false;

			if (!isInputFocused && !isInDropdown) {
				return;
			}
			if (!isOpen) {
				return;
			}

			const maxIndex = filteredOptions.length - 1;
			if (event.key === 'Escape' || event.key === 'Tab') {
				handleClose?.();
				setFocusedIndex(-1);
				return;
			}
			if (event.key === 'ArrowUp' || event.key === 'ArrowDown') {
				event.preventDefault();
				handleArrowKey(event.key === 'ArrowDown' ? 1 : -1, maxIndex);
				return;
			}
			if (event.key === 'Enter' && focusedIndex >= 0 && focusedIndex <= maxIndex) {
				event.preventDefault();
				handleEnterKey();
			}
		},
		[dropdownRef, filteredOptions, focusedIndex, handleArrowKey, handleClose, handleEnterKey, inputRef, isOpen],
	);

	useEffect(() => {
		if (optionsRef?.current && focusedIndex >= 0) {
			// Для groups/selectAll children не совпадает 1:1 с filteredOptions — ищем по классу focused
			const focusedEl = optionsRef.current.querySelector('.focused');
			focusedEl?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
		}
	}, [focusedIndex, optionsRef]);

	useEffect(() => {
		setFocusedIndex(-1);
	}, [filterValue, options]);

	useEffect(() => {
		if (!enableKeyboardNavigation) {
			return;
		}
		document.addEventListener('keydown', handleKeyDown);

		return () => {
			document.removeEventListener('keydown', handleKeyDown);
		};
	}, [enableKeyboardNavigation, handleKeyDown]);

	return [focusedIndex, setFocusedIndex] as const;
};
